def f(expr):
    s = expr.replace(' ', '')
    if not s:
        return 0

    def precedence(op):
        return {'+': 1, '-': 1, '*': 2}.get(op, 0)

    def apply_op(ops, vals):
        op = ops.pop()
        b = vals.pop()
        a = vals.pop()
        if op == '+':
            vals.append(a + b)
        elif op == '-':
            vals.append(a - b)
        else:  # '*'
            vals.append(a * b)

    values = []
    operators = []
    i = 0
    n = len(s)
    while i < n:
        ch = s[i]
        if ch.isdigit():
            num = 0
            while i < n and s[i].isdigit():
                num = num * 10 + int(s[i])
                i += 1
            values.append(num)
            continue
        if ch == '(':
            operators.append(ch)
        elif ch == ')':
            while operators and operators[-1] != '(':
                apply_op(operators, values)
            operators.pop()  # remove '('
        else:  # operator + - *
            while (operators and operators[-1] != '(' and
                   precedence(operators[-1]) >= precedence(ch)):
                apply_op(operators, values)
            operators.append(ch)
        i += 1

    while operators:
        apply_op(operators, values)

    return values[-1]
```

